using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath: modelPath, watchForChanges: true);

var app = builder.Build();

// Train and evaluate model at startup before serving requests
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndEvaluate(dataPath, modelPath);

app.MapControllers();
app.Run();

